package org.apache.commons.math.analysis.solvers;


/**
 * Implements the <em>Regula Falsi</em> or <em>False position</em> method for
 * root-finding (approximating a zero of a univariate real function). It is a
 * modified {@link SecantSolver <em>Secant</em>} method. Unlike the
 * <em>Secant</em> method, convergence is guaranteed by maintaining a
 * bracketed solution.
 *
 * <p>The <em>Regula Falsi</em> method assumes that the function is continuous,
 * but not necessarily smooth.</p>
 *
 * <p>Implementation based on the following article: M. Dowell and P. Jarratt,
 * <em>A modified regula falsi method for computing the root of an
 * equation</em>, BIT Numerical Mathematics, volume 11, number 2,
 * pages 168-174, Springer, 1971.</p>
 *
 * @since 3.0
 * @version $Id$
 */
public class RegulaFalsiSolver extends BaseSecantSolver {

    /** Construct a solver with default accuracy (1e-6). */
    public RegulaFalsiSolver() {
        super(DEFAULT_ABSOLUTE_ACCURACY, Method.REGULA_FALSI);
    }

    /**
     * Construct a solver.
     *
     * @param absoluteAccuracy absolute accuracy
     */
    public RegulaFalsiSolver(final double absoluteAccuracy) {
        super(absoluteAccuracy, Method.REGULA_FALSI);
    }

    /**
     * Construct a solver.
     *
     * @param relativeAccuracy relative accuracy
     * @param absoluteAccuracy absolute accuracy
     */
    public RegulaFalsiSolver(final double relativeAccuracy,
                             final double absoluteAccuracy) {
        super(relativeAccuracy, absoluteAccuracy, Method.REGULA_FALSI);
    }

    /**
     * Construct a solver.
     *
     * @param relativeAccuracy relative accuracy
     * @param absoluteAccuracy absolute accuracy
     * @param functionValueAccuracy Maximum function value error.
     */
    public RegulaFalsiSolver(final double relativeAccuracy,
                             final double absoluteAccuracy,
                             final double functionValueAccuracy) {
        super(relativeAccuracy, absoluteAccuracy, functionValueAccuracy, Method.REGULA_FALSI);
    }
}

package org.apache.commons.math.analysis.solvers.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math.analysis.UnivariateRealFunction;
import org.apache.commons.math.analysis.solvers.RegulaFalsiSolver;
import org.apache.commons.math.analysis.solvers.UnivariateRealSolver;
import org.apache.commons.math.exception.TooManyEvaluationsException;

import static org.junit.Assert.*;

public class StepDefs {
    private UnivariateRealSolver solver;
    private UnivariateRealFunction function;
    private double result;
    private boolean threwException = false;
    private String caughtException = null;

    @Given("a Regula Falsi solver")
    public void a_Regula_Falsi_solver() {
        solver = new RegulaFalsiSolver();
    }

    @Given("the function {string}")
    public void the_function(String functionName) {
        if (functionName.equals("f(x) = exp(x) - pi^3")) {
            function = new UnivariateRealFunction() {
                public double value(double x) {
                    return Math.exp(x) - Math.pow(Math.PI, 3.0);
                }
            };
        } else {
            throw new IllegalArgumentException("Unknown function: " + functionName);
        }
    }

    @When("the solver is called with the interval [{int}, {int}] and maximum {int} evaluations")
    public void the_solver_is_called_with_the_interval_and_maximum_evaluations(Integer lowerBound, Integer upperBound, Integer maxEvals) {
        try {
            result = solver.solve(maxEvals, function, lowerBound, upperBound);
        } catch (TooManyEvaluationsException e) {
            threwException = true;
            caughtException = e.getClass().getSimpleName();
        } catch (Exception e) {
            caughtException = e.getClass().getSimpleName();
        }
    }

    @Then("the solver should return a value approximately {double}")
    public void the_solver_should_return_a_value_approximately(double expectedValue) {
        assertEquals("The solver should return the expected value", expectedValue, result, 1e-15);
    }

    @Then("the solver should not throw a TooManyEvaluationsException")
    public void the_solver_should_not_throw_a_TooManyEvaluationsException() {
        assertFalse("The solver threw TooManyEvaluationsException when it shouldn't have", threwException);
    }
}

