+    int previousCalls = Integer.MAX_VALUE;
+    for (int i = -12; i < -4; ++i) {
+      TestProblem1 pb     = new TestProblem1();
+      double minStep      = 0;
+      double maxStep      = pb.getFinalTime() - pb.getInitialTime();
+      double absTolerance = FastMath.pow(10.0, i);
