+                Type []params = method1.getGenericParameterTypes();
+                try {
+                    class2.getDeclaredMethod(method1.getName(), (Class[]) params);
+                } catch (NoSuchMethodException e) {
+                    allfound = false;
+                    System.out.println(class2.getSimpleName()+" does not implement: "+method1);
+                }
+            }
+        }
